// Статус приглашения пользователя.
// Ref: #/components/schemas/InviteStatus
type InviteStatus string

const (
	InviteStatusConfirmed InviteStatus = "confirmed"
	InviteStatusSent      InviteStatus = "sent"
)

// AllValues returns all InviteStatus values.
func (InviteStatus) AllValues() []InviteStatus {
	return []InviteStatus{
		InviteStatusConfirmed,
		InviteStatusSent,
	}
}

// MarshalText implements encoding.TextMarshaler.
func (s InviteStatus) MarshalText() ([]byte, error) {
	switch s {
	case InviteStatusConfirmed:
		return []byte(s), nil
	case InviteStatusSent:
		return []byte(s), nil
	default:
		return nil, errors.Errorf("invalid value: %q", s)
	}
}

// UnmarshalText implements encoding.TextUnmarshaler.
func (s *InviteStatus) UnmarshalText(data []byte) error {
	switch InviteStatus(data) {
	case InviteStatusConfirmed:
		*s = InviteStatusConfirmed
		return nil
	case InviteStatusSent:
		*s = InviteStatusSent
		return nil
	default:
		return errors.Errorf("invalid value: %q", data)
	}
}

